    ```java
import java.util.ArrayList;

public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
}

class Solution {
    private int sumSubtrees(TreeNode root, ArrayList<Integer> sums) {
        if (root == null) return 0;
        int sum = root.val + sumSubtrees(root.left, sums) + sumSubtrees(root.right, sums);
        sums.add(sum);
        return sum;
    }

    public int maxProduct(TreeNode root) {
        ArrayList<Integer> sums = new ArrayList<>();
        long total = sumSubtrees(root, sums);
        long max_product = 0;

        for (long sum : sums) {
            max_product = Math.max(max_product, sum * (total - sum));
        }

        return (int)(max_product % 1000000007L);
    }
}
```

